import{_ as t,o as i,c as a,ae as s}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"xB77 Hybrid Invoice Protocol (HIP)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/research/HYBRID_INVOICE_PROTOCOL.md","filePath":"docs/research/HYBRID_INVOICE_PROTOCOL.md"}'),n={name:"docs/research/HYBRID_INVOICE_PROTOCOL.md"};function o(r,e,l,h,c,d){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="xb77-hybrid-invoice-protocol-hip" tabindex="-1">xB77 Hybrid Invoice Protocol (HIP) <a class="header-anchor" href="#xb77-hybrid-invoice-protocol-hip" aria-label="Permalink to &quot;xB77 Hybrid Invoice Protocol (HIP)&quot;">​</a></h1><p><strong>Version:</strong> 1.0 (Draft) <strong>Status:</strong> Experimental <strong>Author:</strong> xB77 Research Team</p><h2 id="_1-abstract" tabindex="-1">1. Abstract <a class="header-anchor" href="#_1-abstract" aria-label="Permalink to &quot;1. Abstract&quot;">​</a></h2><p>Cryptographic privacy protocols (like Light Protocol or Tornado Cash) historically suffer from the &quot;Accounting Black Hole&quot; problem: while they successfully obfuscate the transaction graph, they inevitably destroy the semantic context of the transfer (metadata, invoices, tax details). This renders them unusable for compliant enterprise operations.</p><p><strong>xB77 HIP</strong> (Hybrid Invoice Protocol) is a layer-2 standard for embedding encrypted, schema-validated fiscal metadata directly into the shielded state transition, enabling <strong>&quot;Self-Generating Accounting&quot;</strong> without compromising the privacy set.</p><h2 id="_2-the-architecture" tabindex="-1">2. The Architecture <a class="header-anchor" href="#_2-the-architecture" aria-label="Permalink to &quot;2. The Architecture&quot;">​</a></h2><p>The protocol decouples the <strong>Settlement Layer</strong> (Value Transfer) from the <strong>Semantic Layer</strong> (Data Transfer), but binds them atomicity within a single transaction.</p><h3 id="_2-1-the-data-structure-ubl-light" tabindex="-1">2.1. The Data Structure (UBL-Light) <a class="header-anchor" href="#_2-1-the-data-structure-ubl-light" aria-label="Permalink to &quot;2.1. The Data Structure (UBL-Light)&quot;">​</a></h3><p>We utilize a compressed binary variant of the <strong>Universal Business Language (UBL 2.1)</strong> standard.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;ver&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;iv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x9f...a2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Initialization Vector</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;payload&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ENCRYPTED_BLOB&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0x...ff&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // Binding Hash to the ZK-Proof Public Inputs</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_2-2-encryption-scheme" tabindex="-1">2.2. Encryption Scheme <a class="header-anchor" href="#_2-2-encryption-scheme" aria-label="Permalink to &quot;2.2. Encryption Scheme&quot;">​</a></h3><p>We employ a <strong>Hybrid Encryption Scheme (ECIES)</strong> using the recipient&#39;s Solana Public Key (converted to Curve25519) to derive a shared secret.</p><ol><li><strong>Key Exchange:</strong> <code>SharedSecret = ECDH(SenderPriv, ReceiverPub)</code></li><li><strong>Symmetric Key:</strong> <code>K = HKDF(SharedSecret)</code></li><li><strong>Encryption:</strong> <code>Ciphertext = AES-256-GCM(InvoiceJSON, K, IV)</code></li></ol><p>This ensures that <strong>only</strong> the sender and the receiver (and any holder of a Viewing Key) can reconstruct the accounting context.</p><h2 id="_3-the-lifecycle" tabindex="-1">3. The Lifecycle <a class="header-anchor" href="#_3-the-lifecycle" aria-label="Permalink to &quot;3. The Lifecycle&quot;">​</a></h2><h3 id="phase-1-emission-the-sender-agent" tabindex="-1">Phase 1: Emission (The Sender Agent) <a class="header-anchor" href="#phase-1-emission-the-sender-agent" aria-label="Permalink to &quot;Phase 1: Emission (The Sender Agent)&quot;">​</a></h3><ol><li><strong>Context Construction:</strong> The Agent generates the payment (e.g., 50,000 USDC) and the invoice data (Items, VAT, Vendor ID).</li><li><strong>Metadata Embedding:</strong> The invoice data is serialized and encrypted.</li><li><strong>State Compression:</strong> The encrypted blob is stored as a <strong>Compressed State</strong> (or ephemeral Memo) in Light Protocol, atomically linked to the value transfer UTXO.</li></ol><h3 id="phase-2-transmission-the-dark-forest" tabindex="-1">Phase 2: Transmission (The Dark Forest) <a class="header-anchor" href="#phase-2-transmission-the-dark-forest" aria-label="Permalink to &quot;Phase 2: Transmission (The Dark Forest)&quot;">​</a></h3><p>On-chain, observers see only:</p><ul><li>A ZK validity proof.</li><li>Two nullifiers (spent notes).</li><li>Two new commitments (output notes).</li><li><strong>No visible amount, no recipient, no invoice data.</strong></li></ul><h3 id="phase-3-reconstruction-the-receiver-agent" tabindex="-1">Phase 3: Reconstruction (The Receiver Agent) <a class="header-anchor" href="#phase-3-reconstruction-the-receiver-agent" aria-label="Permalink to &quot;Phase 3: Reconstruction (The Receiver Agent)&quot;">​</a></h3><ol><li><strong>Scanning:</strong> The Receiver&#39;s &quot;Listener&quot; scans the chain using its <code>IncomingViewKey</code>.</li><li><strong>Detection:</strong> It identifies a UTXO belonging to it.</li><li><strong>Extraction:</strong> It retrieves the associated encrypted metadata state.</li><li><strong>Decryption:</strong> Using the Wallet&#39;s <code>PrivateKey</code>, it decrypts the blob back into the UBL JSON.</li><li><strong>Reconciliation:</strong> The system validates that <code>Invoice.total == UTXO.amount</code>. If valid, it triggers the &quot;Invoice Received&quot; event in the Hub.</li></ol><h2 id="_4-compliance-selective-disclosure" tabindex="-1">4. Compliance &amp; Selective Disclosure <a class="header-anchor" href="#_4-compliance-selective-disclosure" aria-label="Permalink to &quot;4. Compliance &amp; Selective Disclosure&quot;">​</a></h2><p>The &quot;Killer Feature&quot; for institutional adoption is the <strong>Audit Key</strong>.</p><p>An enterprise can share a specific <code>AuditViewKey</code> with a regulator or auditor. This key allows <strong>read-only access</strong> to decrypt the metadata (Invoices) without giving the ability to spend funds. This turns a &quot;Dark Wallet&quot; into a &quot;Transparently Compliant Vault&quot; instantly.</p><h2 id="_5-implementation-status" tabindex="-1">5. Implementation Status <a class="header-anchor" href="#_5-implementation-status" aria-label="Permalink to &quot;5. Implementation Status&quot;">​</a></h2><ul><li>[x] <strong>Mock Implementation:</strong> SQLite storage with simulated encryption (Live in Hub).</li><li>[ ] <strong>On-Chain Integration:</strong> Light Protocol custom PDA for metadata storage.</li><li>[ ] <strong>Standardization:</strong> Defining the compact-UBL schema for Solana.</li></ul><hr><p><em>Built with ️ for the Solana Privacy Hackathon 2026.</em></p>`,29)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
